def pagerank_simplified(graph, damping_factor=0.85, iterations=100):
    all_pages = set()
    for page, links in graph.items():
        all_pages.add(page)
        for link in links:
            all_pages.add(link)
    all_pages = sorted(list(all_pages))

    N = len(all_pages)
    if N == 0:
        return {}

    pagerank = {page: 1.0 / N for page in all_pages}

    out_degrees = {page: len(graph.get(page, [])) for page in all_pages}

    for _ in range(iterations):
        new_pagerank = {}

        sink_pagerank_sum = 0
        for page in all_pages:
            if out_degrees[page] == 0:
                sink_pagerank_sum += pagerank[page]

        for page in all_pages:
            rank_sum = (1 - damping_factor) / N
            rank_sum += damping_factor * (sink_pagerank_sum / N)

            for incoming_page in all_pages:
                if page in graph.get(incoming_page, []):
                    if out_degrees[incoming_page] > 0:
                        rank_sum += damping_factor * (pagerank[incoming_page] / out_degrees[incoming_page])

            new_pagerank[page] = rank_sum

        pagerank = new_pagerank

    return pagerank
